import React, { useEffect, useState } from 'react';
import PendingSubmissions from './pages/PendingSubmissions';
import RhymesList from './pages/RhymesList';
import GiftsList from './pages/GiftsList';
import UsersList from './pages/UsersList';
import AddressesList from './pages/AddressesList';
import AuditLogs from './pages/AuditLogs';

const ACTIVE_PAGE_KEY = 'ginj-admin-active-page';

function App() {
  const [currentPage, setCurrentPage] = useState(() => localStorage.getItem(ACTIVE_PAGE_KEY) || 'pending');

  useEffect(() => {
    localStorage.setItem(ACTIVE_PAGE_KEY, currentPage);
  }, [currentPage]);

  const menuItems = [
    { id: 'pending', label: 'Applications', icon: '📋' },
    { id: 'rhymes', label: 'Gurbani List', icon: '🎵' },
    { id: 'gifts', label: 'Prize List', icon: '🎁' },
    { id: 'users', label: 'Participants', icon: '👥' },
    { id: 'addresses', label: 'Participant Address List', icon: '🏠' },
    { id: 'auditLogs', label: 'Audit Logs', icon: '📊' },
  ];

  const getPageTitle = () => {
    const item = menuItems.find(m => m.id === currentPage);
    return item ? item.label : 'GINJ Admin';
  };

  return (
    <div style={{ display: 'flex', fontFamily: 'Arial, sans-serif', minHeight: '100vh' }}>
      {/* Sidebar */}
      <div style={{
        width: '220px',
        backgroundColor: '#1e3a8a',
        color: 'white',
        padding: '24px 0',
        boxShadow: '2px 0 8px rgba(0,0,0,0.1)',
        minHeight: '100vh'
      }}>
        <h2 style={{ padding: '0 16px 24px', margin: 0, fontSize: '18px', fontWeight: '600' }}>
          GINJ Admin
        </h2>
        <nav>
          {menuItems.map(item => (
            <button
              key={item.id}
              onClick={() => setCurrentPage(item.id)}
              style={{
                display: 'block',
                width: '100%',
                padding: '12px 16px',
                border: 'none',
                backgroundColor: currentPage === item.id ? '#3b82f6' : 'transparent',
                color: 'white',
                textAlign: 'left',
                cursor: 'pointer',
                fontSize: '14px',
                fontWeight: currentPage === item.id ? '600' : '500',
                transition: 'background-color 0.2s',
              }}
              onMouseEnter={(e) => e.target.style.backgroundColor = currentPage === item.id ? '#3b82f6' : '#1e5a96'}
              onMouseLeave={(e) => e.target.style.backgroundColor = currentPage === item.id ? '#3b82f6' : 'transparent'}
            >
              <span style={{ marginRight: '8px' }}>{item.icon}</span>
              {item.label}
            </button>
          ))}
        </nav>
      </div>

      {/* Main Content */}
      <div style={{
        flex: 1,
        padding: '24px',
        backgroundColor: '#f9fafb',
        overflowY: 'auto'
      }}>
        <h1 style={{ marginTop: 0, color: '#1f2937', marginBottom: '24px' }}>
          {getPageTitle()}
        </h1>
        {currentPage === 'pending' && <PendingSubmissions />}
        {currentPage === 'rhymes' && <RhymesList />}
        {currentPage === 'gifts' && <GiftsList />}
        {currentPage === 'users' && <UsersList />}
        {currentPage === 'addresses' && <AddressesList />}
        {currentPage === 'auditLogs' && <AuditLogs />}
      </div>
    </div>
  );
}

export default App;
